CREATE   Procedure [RSU].[spAutoGen_UserResourceAddresses_UPDATE]
(
		@UserResourceAddressID INT		
		, @PoliticalStateId VARCHAR(4)		
		, @PoliticalCountryId NVARCHAR(10)		
		, @PoliticalTimeZoneId INT		
		, @StreetAddress NVARCHAR(50)		
		, @StreetAddress2 NVARCHAR(50)		
		, @City NVARCHAR(50)		
		, @PostalCode NVARCHAR(10)		
		, @PlusFour NVARCHAR(4)		
		, @IsActive BIT		
		, @ModifiedDate DATETIMEOFFSET		
		, @ModifiedById UNIQUEIDENTIFIER		
		, @CreatedDate DATETIMEOFFSET		
		, @CreatedById UNIQUEIDENTIFIER
)
AS
BEGIN
	/**************
	 * INITIALIZE
	 **************/
	 DECLARE @ACLUserID UNIQUEIDENTIFIER = CAST(CONTEXT_INFO() AS UNIQUEIDENTIFIER)
		, @UserGUID NVARCHAR(MAX)
		, @CreatedAccessId SMALLINT;

	/*********************
	 * CHECK ACCESS LEVEL
	 *********************/
	 IF (NOT EXISTS(SELECT * FROM [GEN].fxGetAccessLevel('UPDATE','RSU','UserResourceAddresses') AS AL WHERE (AL.UpdateAccessId > 0))) BEGIN
		--** Get ACL Information
		--SELECT @ACLUserID = UserId, @UserGUID = @UserGUID, @CreatedAccessId = AL.UpdateAccessId  FROM [GEN].fxGetAccessLevel('UPDATE','RSU','UserResourceAddresses') AS AL WHERE (AL.UpdateAccessId > 0)

		--** Check that there is a user
		SELECT TOP 1 @UserGUID = UserGuidIDMasked FROM [GEN].fxGetUserInfo();

		RAISERROR (N'[50120]|The user "%s" does not have UPDATE privileges on table "%s".'
           , 18 -- Severity,
           , 1 -- State,
           , @UserGUID
		   , N'[RSU].[UserResourceAddresses]');
		RETURN;
	 END

	 /************
	 * UPDATE ROW
	 ************/
	 UPDATE RSU.UserResourceAddresses SET
		[PoliticalStateId] = @PoliticalStateId
		, [PoliticalCountryId] = @PoliticalCountryId
		, [PoliticalTimeZoneId] = @PoliticalTimeZoneId
		, [StreetAddress] = @StreetAddress
		, [StreetAddress2] = @StreetAddress2
		, [City] = @City
		, [PostalCode] = @PostalCode
		, [PlusFour] = @PlusFour
		, [IsActive] = @IsActive
		, [ModifiedDate] = SYSDATETIMEOFFSET()
		, [ModifiedById] = UTL.fxGetDefaultGuidId(@ModifiedById)
	 WHERE
		(UserResourceAddressID = @UserResourceAddressID);

	 /**************
	 * RETURN ROW
	 **************/
	 SELECT * FROM RSU.UserResourceAddresses
	 WHERE
		(UserResourceAddressID = @UserResourceAddressID);

END;

GO
